const CustomIcons = {
  shoes: ShoesIcon,
  trending: TrendingIcon,
  new: NewIcon,
  heart: HeartIcon,
  heartFill: HeartFillIcon,
};

/**
 * Mapping for Hugeicons.
 */
const HUGE_MAPPING: Record<string, any> = {
  "house.fill": Home03Icon,
  "paperplane.fill": SentIcon,
  "chevron.left.forwardslash.chevron.right": SourceCodeIcon,
  "chevron.left": ArrowLeft01Icon,
  "chevron.right": ArrowRight01Icon,
  "person.fill": UserIcon,
  magnifyingglass: Search01Icon,
  suit: Suit02Icon,
  dress: Dress03Icon,
  shoes: CustomIcons.shoes,
  trending: CustomIcons.trending,
  joggers: JoggerPantsIcon,
  purse: Purse01Icon,
  hat: HatIcon,
  perfume: PerfumeIcon,
  shorts: ShortsPantsIcon,
  bag: ShoppingBag01Icon,
  "bag.fill": ShoppingBag01Icon,
  heart: CustomIcons.heart,
  "heart.fill": CustomIcons.heartFill,
  plus: Add01Icon,
  store: Store02Icon,
  "3d-rotate": ThreeDRotateIcon,
  kid: BabyBoyDressIcon,
  sale: SaleTag02Icon,
  accessories: NecklaceIcon,
  new: NewIcon,
  xmark: Cancel01Icon,
  rate: StarIcon,
  inbox: InboxIcon,
  "square.and.arrow.up": Share01Icon,
  ellipsis: MoreHorizontalIcon,
};

export type IconSymbolName =
  | "house.fill"
  | "paperplane.fill"
  | "chevron.left.forwardslash.chevron.right"
  | "chevron.right"
  | "person.fill"
  | "magnifyingglass"
  | "suit"
  | "dress"
  | "shoes"
  | "trending"
  | "joggers"
  | "purse"
  | "hat"
  | "perfume"
  | "shorts"
  | "bag"
  | "heart"
  | "heart.fill"
  | "plus"
  | "store"
  | "3d-rotate"
  | "kid"
  | "sale"
  | "accessories"
  | "new"
  | "xmark"
  | "inbox"
  | "square.and.arrow.up"
  | "ellipsis"
  | string;

/**
 * An icon component that uses Hugeicons across platforms.
 */
export function IconSymbol({
  name,
  size = 24,
  color,
  style,
}: {
  name: IconSymbolName;
  size?: number;
  color: string;
  style?: StyleProp<ViewStyle>;
  weight?: SymbolWeight;
}) {
  const iconSource = HUGE_MAPPING[name];
  if (!iconSource) return null;

  // Handle custom functional components (ShoesIcon, TrendingIcon)
  if (typeof iconSource === "function") {
    const CustomIcon = iconSource;
    return (
      <View style={style}>
        <CustomIcon color={color} size={size} />
      </View>
    );
  }

  // Handle custom SVG icons (required assets)
  if (
    typeof iconSource === "number" ||
    (typeof iconSource === "object" && iconSource?.uri)
  ) {
    return (
      <View style={style}>
        <Image
          source={iconSource}
          style={{ width: size, height: size, tintColor: color }}
          contentFit="contain"
        />
      </View>
    );
  }

  return (
    <HugeiconsIcon
      icon={iconSource}
      size={size}
      color={color}
      strokeWidth={1.25}
    />
  );
}
